+/// Configuration values collected from wizard.
+struct ConfigValues {
+    log_level: String,
+    socket_path: String,
+    confidence_threshold: f64,
+    min_local_time_ms: u32,
+    compression_level: u8,
+}
+
+/// Worker definition collected from wizard.
+struct WizardWorker {
+    id: String,
+    host: String,
+    user: String,
+    identity_file: String,
